"""Чисто логическая ошибка (off-by-one), которую статический анализ
по определению не видит - её обязан поймать LLM-слой."""
def average_last_n(values, n):
    # БАГ: должно быть values[-n:], а не values[-n-1:]
    # из-за этого в среднее попадает один лишний элемент
    window = values[-n - 1:]
    return sum(window) / n
